UPDATE workflows
SET steps = '[{"goal":"Content Research & Curation","step":1,"tools":[{"name":"Perplexity AI","slug":"perplexity-ai"},{"name":"ChatGPT","slug":"chatgpt"}],"description":"Use <strong>Perplexity AI</strong> to summarize weekly industry news and <strong>ChatGPT</strong> to curate the top 3 stories. Prompt Perplexity: <em>''Find the top 5 trending tech news articles from this week with sources.''</em><br><br>💡 <strong>Pro tip:</strong> This guarantees completely factual, up-to-date curation."},{"goal":"Newsletter Copy Writing","step":2,"tools":[{"name":"Claude AI","slug":"claude-ai"},{"name":"Jasper","slug":"jasper"}],"description":"Draft the newsletter in your brand''s voice via <strong>Claude AI</strong> or <strong>Jasper</strong>.<br><br>💡 <strong>Pro tip:</strong> Feed Claude your past 3 newsletters and tell it to ''Extract the tone constraints and apply them to this new draft'' to maintain perfect brand consistency."},{"goal":"Design & Layout","step":3,"tools":[{"name":"Canva AI","slug":"canva"},{"name":"Adobe Firefly","slug":"adobe-firefly"}],"description":"Format the content into a visually appealing template using <strong>Canva AI</strong> elements or <strong>Adobe Firefly</strong> graphics.<br><br>💡 <strong>Pro tip:</strong> Keep image file sizes under 100kb so your newsletter loads instantly on mobile devices and avoids Gmail''s promotional tab."},{"goal":"Personalization & A/B Testing","step":4,"tools":[{"name":"Copy.ai","slug":"copy-ai"},{"name":"Grammarly","slug":"grammarly"}],"description":"Run A/B tests on 3 different subject lines generated by <strong>Copy.ai</strong>, checking them in <strong>Grammarly</strong> for punchiness.<br><br>💡 <strong>Pro tip:</strong> The best subject lines evoke curiosity. Keep them under 40 characters so they don''t get cut off on mobile screens."},{"goal":"Send Automation & Analytics","step":5,"tools":[{"name":"n8n","slug":"n8n"},{"name":"Activepieces","slug":"activepieces"}],"description":"Connect your content feeds to <strong>Activepieces</strong> or <strong>n8n</strong> to automatically pull live data and schedule your Mailchimp sends.<br><br>💡 <strong>Pro tip:</strong> Activepieces offers a highly visual, user-friendly drag-and-drop builder for folks who find n8n too complex."}]'::jsonb
