UPDATE workflows
SET steps = '[{"goal":"Idea Research & Market Analysis","step":1,"tools":[{"name":"Perplexity AI","slug":"perplexity-ai"},{"name":"ChatGPT","slug":"chatgpt"}],"description":"Analyze Amazon Kindle trends using <strong>Perplexity AI</strong>, then generate chapter outlines using <strong>ChatGPT</strong>. Prompt: <em>''Act as a NYT bestselling author. Outline a 10-chapter non-fiction book on [topic].''</em><br><br>💡 <strong>Pro tip:</strong> Ensure each chapter solves a specific problem."},{"goal":"Outline & Structure Design","step":2,"tools":[{"name":"Claude AI","slug":"claude-ai"},{"name":"Notion AI","slug":"notion-ai"}],"description":"Map out character arcs or detailed section notes in <strong>Notion AI</strong> and use <strong>Claude AI</strong> to expand the ideas.<br><br>💡 <strong>Pro tip:</strong> Claude AI has a massive context window, meaning you can paste your entire 30,000-word draft in it to check for plot holes."},{"goal":"AI-Assisted Writing & Drafting","step":3,"tools":[{"name":"Jasper","slug":"jasper"},{"name":"ChatGPT","slug":"chatgpt"}],"description":"Draft the chapters using <strong>Jasper''s</strong> long-form writing assistant or <strong>ChatGPT</strong>, checking word counts as you go.<br><br>💡 <strong>Pro tip:</strong> Jasper''s ''Boss Mode'' is explicitly designed to keep the AI focused over long documents without losing the narrative thread."},{"goal":"Editing & Proofreading","step":4,"tools":[{"name":"Grammarly","slug":"grammarly"},{"name":"ProWritingAid","slug":"prowritingaid"}],"description":"Polishing is crucial: Run your manuscript through <strong>ProWritingAid</strong> or <strong>Grammarly</strong> to eliminate passive voice and fix dialogue tags.<br><br>💡 <strong>Pro tip:</strong> ProWritingAid''s ''Sticky Sentence'' report is incredible for finding and fixing clunky, hard-to-read paragraphs."},{"goal":"Book Cover Design","step":5,"tools":[{"name":"Canva AI","slug":"canva"},{"name":"Midjourney","slug":"midjourney"}],"description":"Prompt <strong>Midjourney</strong> or <strong>Canva AI</strong> for book covers. Prompt Midjourney: <em>''Minimalist typography book cover, vector art, thriller vibes --ar 2:3''</em>.<br><br>💡 <strong>Pro tip:</strong> Always test your generated book cover as a tiny thumbnail to ensure it pops on Amazon search."}]'::jsonb
